import React from "react";
import { Link } from "gatsby";
import { LayoutProse } from "src/components/layouts/layout";
import { SeoDefault } from "src/components/Seo";

const ArchivingStatementPage = () => {
  return (
    <LayoutProse pageTitle="Archiving Statement" extraClass="sans-pretty">
      <div id="archiving-statement" className="g-pretty-p">
        <p>
          Disclaimer — This website primarily organizes content related to my{" "}
          <Link to="/" title="Home">
            portfolio
          </Link>{" "}
          and{" "}
          <Link to="/blog" title="Blog">
            blog
          </Link>
          . Credit is given to the original creators of non-owned content. I
          follow copyright guidelines for content creation and embedding.
        </p>
        <p>
          Feel free to{" "}
          <Link to="/contact" title="Contact">
            reach out
          </Link>{" "}
          with any questions — I’m here to help.
        </p>
        <p>
          Please note that links and elements may occasionally not work, and
          this disclaimer may change without notice.
        </p>
      </div>
    </LayoutProse>
  );
};

export default ArchivingStatementPage;

export const Head = () => <SeoDefault title="Archiving Statement" />;
